import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as a,c as d,e as c}from"./app-be253e4c.js";const o={},r=c('<h1 id="异步模块模式" tabindex="-1"><a class="header-anchor" href="#异步模块模式" aria-hidden="true">#</a> 异步模块模式</h1><p>异步模块模式<code>AMD</code> 是当请求发出后，继续其他业务逻辑，直到模块加载完成执行后续逻辑，实现模块开发中的对模块加载完成后的引用，大名鼎鼎的<code>require.js</code> 就是以它为思想的，异步模块模式不属于一般定义的<code>23</code>种设计模式的范畴，而通常将其看作广义上的架构型设计模式。</p><h2 id="基本介绍" tabindex="-1"><a class="header-anchor" href="#基本介绍" aria-hidden="true">#</a> 基本介绍</h2><p>异步模块模式主要是用在浏览器环境中，浏览器环境不同于服务器环境，为了不阻塞渲染线程通常以异步的方式来加载外部<code>Js</code> 文件，因此要使用文件中的某些模块方法必须要经历文件加载过程，而对于这种问题同步模块模式则无法适用，需要使用异步模块模式。异步模块模式不仅减少了多人开发过程中变量、方法名被覆盖的问题，而且增加了模块依赖，使开发者不必担心某些方法尚未加载或未加载完成造成的无法使用问题，异步加载部分功能也可以将更多首屏不必要的功能剥离出去，减少首屏加载成本。</p><h2 id="代码实现" tabindex="-1"><a class="header-anchor" href="#代码实现" aria-hidden="true">#</a> 代码实现</h2>',5),t=[r];function n(s,h){return a(),d("div",null,t)}const l=e(o,[["render",n],["__file","async-module-mode.html.vue"]]);export{l as default};
